import numpy as np
from typing import Tuple

class LinearCode:
    def __init__(self, G: np.ndarray):
        self.G = G % 2
        self.k, self.n = G.shape
        self.r = self.n - self.k
        self.H = self.compute_parity_check()

    def compute_parity_check(self) -> np.ndarray:
        # Put G in systematic form [I_k | P]
        G_sys = self.G.copy()
        for col in range(self.k):
            pivot = None
            for row in range(col, self.k):
                if G_sys[row, col] == 1:
                    pivot = row
                    break
            if pivot is None:
                continue
            G_sys[[col, pivot]] = G_sys[[pivot, col]]
            for row in range(self.k):
                if row != col and G_sys[row, col] == 1:
                    G_sys[row] = (G_sys[row] + G_sys[col]) % 2

        P = G_sys[:, self.k:]
        I_r = np.eye(self.r, dtype=int)
        return np.hstack([P.T, I_r]) % 2

    def encode(self, message: np.ndarray) -> np.ndarray:
        return (message @ self.G) % 2

    def syndrome(self, received: np.ndarray) -> np.ndarray:
        return (self.H @ received) % 2

    def is_codeword(self, word: np.ndarray) -> bool:
        return np.all(self.syndrome(word) == 0)

import numpy as np
from typing import Optional, Tuple, List
from itertools import combinations

class SyndromeDecoder:
    def __init__(self, code, max_weight: int):
        self.code = code
        self.max_weight = max_weight
        self.table = self.build_table()

    def build_table(self) -> dict:
        table = {}
        n = self.code.n
        zero_syn = tuple([0] * self.code.r)
        table[zero_syn] = np.zeros(n, dtype=int)

        for w in range(1, self.max_weight + 1):
            for pos in combinations(range(n), w):
                e = np.zeros(n, dtype=int)
                for p in pos:
                    e[p] = 1
                syn = tuple(self.code.syndrome(e))
                if syn not in table:
                    table[syn] = e.copy()
        return table

    def decode(self, received: np.ndarray) -> Tuple[Optional[np.ndarray], np.ndarray]:
        syn = tuple(self.code.syndrome(received))
        if syn not in self.table:
            return None, received
        error = self.table[syn]
        codeword = (received + error) % 2
        return codeword[:self.code.k], error

import numpy as np

def hamming_weight(x: np.ndarray) -> int:
    return int(np.sum(x != 0))

def hamming_distance(x: np.ndarray, y: np.ndarray) -> int:
    return int(np.sum((x + y) % 2))

def minimum_distance(code) -> int:
    min_wt = code.n + 1
    for i in range(1, 2**code.k):
        msg = np.array([(i >> j) & 1 for j in range(code.k)])
        cw = code.encode(msg)
        wt = hamming_weight(cw)
        if wt < min_wt:
            min_wt = wt
    return min_wt

import numpy as np
from typing import Optional

class SimpleISD:
    def __init__(self, H: np.ndarray, max_iter: int = 1000):
        self.H = H % 2
        self.r, self.n = H.shape
        self.k = self.n - self.r
        self.max_iter = max_iter

    def solve(self, syndrome: np.ndarray, target_weight: int) -> Optional[np.ndarray]:
        s = syndrome % 2

        for _ in range(self.max_iter):
            perm = np.random.permutation(self.n)
            H_p = self.H[:, perm]
            H_r = H_p[:, self.k:]

            # Try to invert H_r
            aug = np.hstack([H_r, np.eye(self.r, dtype=int)]) % 2
            try:
                for col in range(self.r):
                    pivot = None
                    for row in range(col, self.r):
                        if aug[row, col] == 1:
                            pivot = row
                            break
                    if pivot is None:
                        raise ValueError()
                    aug[[col, pivot]] = aug[[pivot, col]]
                    for row in range(self.r):
                        if row != col and aug[row, col] == 1:
                            aug[row] = (aug[row] + aug[col]) % 2

                H_r_inv = aug[:, self.r:]
                e_r = (H_r_inv @ s) % 2

                if np.sum(e_r) == target_weight:
                    e_perm = np.zeros(self.n, dtype=int)
                    e_perm[self.k:] = e_r
                    e = np.zeros(self.n, dtype=int)
                    for i, p in enumerate(perm):
                        e[p] = e_perm[i]
                    if np.array_equal((self.H @ e) % 2, s):
                        return e
            except:
                continue
        return None
